  constructor(usageService, snackBar) {
    this.usageService = usageService;
    this.snackBar = snackBar;
    this.loading = true;
    this.today = new Date();
    this.fromDate = null;
    this.toDate = null;
    this.categories = ['Raw Materials', 'Packing Materials', 'Chicken', 'Mutton', 'Fish & Prawns', 'Butter, Cheese, Cream', 'Cool Drinks & Water Bottles', 'Sanitary'];
    this.displayedColumns = [];
    this.dataSource = [];
    // =====================================================
    // KPI VARIABLES
    // =====================================================
    this.totalConsumption = 0;
    this.topDepartment = '-';
    this.highestCategory = '-';
    this.averageDailyUsage = 0;
  }
  // =====================================================
  // INIT
  // =====================================================
  ngOnInit() {
    this.displayedColumns = ['department', ...this.categories, 'total'];
    const today = new Date();
    this.toDate = today;
    this.fromDate = new Date(today.getFullYear(), today.getMonth(), 1);
    this.loadReport();
  }
